/* Renders WC26 (see data.js, generated by scripts/05_export_site_data.py). */

const FLAGS = {
  "Algeria": "🇩🇿", "Argentina": "🇦🇷", "Australia": "🇦🇺", "Austria": "🇦🇹",
  "Belgium": "🇧🇪", "Bosnia and Herzegovina": "🇧🇦", "Brazil": "🇧🇷",
  "Canada": "🇨🇦", "Cape Verde": "🇨🇻", "Colombia": "🇨🇴", "Croatia": "🇭🇷",
  "Curaçao": "🇨🇼", "Czech Republic": "🇨🇿", "DR Congo": "🇨🇩", "Ecuador": "🇪🇨",
  "Egypt": "🇪🇬", "England": "🏴󠁧󠁢󠁥󠁮󠁧󠁿", "France": "🇫🇷", "Germany": "🇩🇪",
  "Ghana": "🇬🇭", "Haiti": "🇭🇹", "Iran": "🇮🇷", "Iraq": "🇮🇶",
  "Ivory Coast": "🇨🇮", "Japan": "🇯🇵", "Jordan": "🇯🇴", "Mexico": "🇲🇽",
  "Morocco": "🇲🇦", "Netherlands": "🇳🇱", "New Zealand": "🇳🇿", "Norway": "🇳🇴",
  "Panama": "🇵🇦", "Paraguay": "🇵🇾", "Portugal": "🇵🇹", "Qatar": "🇶🇦",
  "Saudi Arabia": "🇸🇦", "Scotland": "🏴󠁧󠁢󠁳󠁣󠁴󠁿", "Senegal": "🇸🇳",
  "South Africa": "🇿🇦", "South Korea": "🇰🇷", "Spain": "🇪🇸", "Sweden": "🇸🇪",
  "Switzerland": "🇨🇭", "Tunisia": "🇹🇳", "Turkey": "🇹🇷",
  "United States": "🇺🇸", "Uruguay": "🇺🇾", "Uzbekistan": "🇺🇿",
};

const pct = (x, d = 1) => (100 * x).toFixed(d) + "%";
const flag = (t) => `<span class="flag">${FLAGS[t] || "🏳️"}</span>`;
const TLA3 = (t) => ({ "United States": "USA", "South Korea": "KOR", "South Africa": "RSA",
  "Saudi Arabia": "KSA", "Czech Republic": "CZE", "Bosnia and Herzegovina": "BIH",
  "Ivory Coast": "CIV", "DR Congo": "COD", "Cape Verde": "CPV", "New Zealand": "NZL",
  "Netherlands": "NED" }[t] || (t || "?").slice(0, 3).toUpperCase());
const byChamp = [...WC26.teams].sort((a, b) => b.P_champion - a.P_champion);
const $ = (id) => document.getElementById(id);

/* ---------- per-match score-distribution heatmap (scripts/36) ---------- */
const MD = {};
(WC26.match_dists || []).forEach((m) => { MD[m.home + "|" + m.away] = m; });
// upcoming matches (scripts/42) are heatmap-able too, fold them into the index
((WC26.next_matches && WC26.next_matches.matches) || []).forEach((m) => {
  MD[m.home + "|" + m.away] = {
    home: m.home, away: m.away, group: m.ko ? "Knockout" : "Group", city: m.city || null,
    lh: m.model.lh, la: m.model.la, pH: m.model.pH, pD: m.model.pD, pA: m.model.pA,
    grid: m.grid, top: m.top, actual: null,
  };
});
// predicted bracket ties (scripts/43), click a knockout tie -> its heatmap;
// played ties carry their real 90' score and who advanced (shootouts resolved)
(WC26.bracket_dists || []).forEach((m) => {
  const kv = (WC26.ko_venues || {})[m.match];
  MD[m.home + "|" + m.away] = {
    home: m.home, away: m.away, group: "Knockout", city: (kv && kv.c) || null,
    lh: m.lh, la: m.la, pH: m.pH, pD: m.pD, pA: m.pA, grid: m.grid, top: m.top,
    actual: m.actual || null, winner: m.winner || null,
  };
});
// venue label: host-country flag + city + elevation (only stated when it bites)
const venueTag = (city) => {
  if (!city) return "";
  const cm = (WC26.city_meta || {})[city];
  if (!cm) return city;
  return `${flag(cm.country)}${city}${cm.alt >= 100 ? ` · ${cm.alt.toLocaleString("en")} m` : ""}`;
};

/* ---------- client-side goal model (exported DC point estimate) ----------
   Lets the site build the SAME score grid for ANY pairing — sandbox picks
   included — with the maths of scripts/43: neutral knockout venue, fatigue
   tilt in, Dixon-Coles low-score correction. Computed once per pair, cached
   into the MD index so downstream code can't tell it from a precomputed one. */
const DCP = WC26.dc_params || null;
const KOV = WC26.ko_venues || {};
const CTILT = WC26.city_tilt || {};
const TELO = {}; (WC26.teams || []).forEach((t) => { TELO[t.team] = t.elo; });
const FTILT = {};
if (WC26.fatigue && WC26.fatigue.meta && WC26.fatigue.z) {
  Object.entries(WC26.fatigue.z).forEach(([t, z]) => { FTILT[t] = WC26.fatigue.meta.beta_fatigue * z; });
}
function dcDist(home, away, mn) {
  if (!DCP || TELO[home] == null || TELO[away] == null) return null;
  // venue-aware like the Monte Carlo: at match `mn` the host nation (if playing)
  // takes a true home side, and the altitude city tilt applies at high venues.
  const kv = mn != null ? KOV[mn] : null;
  const ven = kv ? kv.v : "", city = kv ? kv.c : null;
  const h = away === ven ? away : home, aw = h === home ? away : home;
  const isHome = h === ven ? 1 : 0;
  const lin = DCP.beta_elo * (TELO[h] - TELO[aw]) / 400;
  const d = (FTILT[h] || 0) - (FTILT[aw] || 0)
    + (city ? (CTILT[h + "|" + city] || 0) - (CTILT[aw + "|" + city] || 0) : 0);
  let lh = Math.exp(DCP.beta0 + DCP.beta_home * isHome + lin + d);
  let la = Math.exp(DCP.beta0 + DCP.beta_away * isHome - lin - d);
  if (h !== home) { const sw = lh; lh = la; la = sw; }  // reorient to (home, away)
  const pois = (lam) => { const o = [Math.exp(-lam)]; for (let i = 1; i <= 10; i++) o.push(o[i - 1] * lam / i); return o; };
  const ph = pois(lh), pa = pois(la);
  const M = ph.map((p) => pa.map((q) => p * q));
  M[0][0] *= 1 - lh * la * DCP.rho; M[0][1] *= 1 + lh * DCP.rho;
  M[1][0] *= 1 + la * DCP.rho; M[1][1] *= 1 - DCP.rho;
  let S = 0; M.forEach((r) => r.forEach((v) => { S += v; }));
  let pH = 0, pD = 0, pA = 0;
  const grid = Array.from({ length: 6 }, () => Array(6).fill(0));
  for (let i = 0; i <= 10; i++) for (let j = 0; j <= 10; j++) {
    const v = M[i][j] / S;
    if (i > j) pH += v; else if (i < j) pA += v; else pD += v;
    grid[Math.min(i, 5)][Math.min(j, 5)] += v;
  }
  const flat = [];
  for (let i = 0; i < 6; i++) for (let j = 0; j < 6; j++) flat.push({ h: i, a: j, p: grid[i][j] });
  flat.sort((x, y) => y.p - x.p);
  return { home, away, group: "Knockout", city: city || null,
    lh: Math.round(100 * lh) / 100, la: Math.round(100 * la) / 100,
    pH, pD, pA, grid, top: flat.slice(0, 3), actual: null };
}
const getDist = (a, b, mn) => MD[a + "|" + b] || MD[b + "|" + a] || (MD[a + "|" + b] = dcDist(a, b, mn));
// P(a goes through tie `mn` vs b): 90' win + the proportional draw split,
// venue-aware and DETERMINISTIC — the identical formula the pipeline uses to
// propagate winners, so the quoted favourite is always the team that advances,
// and the number never wobbles from one slider position to the next.
const tieShare = (a, b, mn) => {
  const m = dcDist(a, b, mn);
  if (!m) return null;
  return m.pH + m.pD * (m.pH / (m.pH + m.pA || 1));
};

// a fixture is a "coin-flip" when no single W/D/L outcome clears 42%, i.e. the
// model genuinely can't separate the sides. Returns the badge HTML or "".
const coinFlipBadge = (home, away) => {
  const m = MD[home + "|" + away];
  if (!m) return "";
  const top = Math.max(m.pH, m.pD, m.pA);
  return top < 0.42 ? `<span class="cf-badge" title="This single match: pre-match the model gave no result above ${pct(top,0)}, a coin-flip">⚖ coin-flip</span>` : "";
};

function showHeat(home, away) {
  const m = MD[home + "|" + away];
  if (!m) return;
  let ov = $("mh-overlay");
  if (!ov) {
    ov = document.createElement("div");
    ov.id = "mh-overlay"; ov.className = "mh-overlay";
    document.body.appendChild(ov);
    ov.addEventListener("click", (e) => { if (e.target === ov) ov.classList.remove("show"); });
    document.addEventListener("keydown", (e) => { if (e.key === "Escape") ov.classList.remove("show"); });
  }
  const G = m.grid, maxp = Math.max(...G.flat());
  const lab = (i) => (i === 5 ? "5+" : "" + i);
  // tint: home win (h>a) green, away win (h<a) pink, draw (h==a) slate; alpha by p
  const tint = (h, a, p) => {
    const al = (0.08 + 0.92 * (p / maxp)).toFixed(3);
    if (h > a) return `rgba(54, 245, 160, ${al})`;   // home win, neon green
    if (h < a) return `rgba(255, 93, 115, ${al})`;   // away win, hot
    return `rgba(131, 152, 189, ${al})`;             // draw, slate
  };
  let cells = `<div class="axlabel"></div>` +
    [0, 1, 2, 3, 4, 5].map((a) => `<div class="axlabel">${lab(a)}</div>`).join("");
  for (let h = 0; h <= 5; h++) {
    cells += `<div class="axlabel row">${lab(h)}</div>`;
    for (let a = 0; a <= 5; a++) {
      const p = G[h][a];
      const isModal = m.top[0].h === h && m.top[0].a === a;
      const isAct = m.actual && m.actual[0] === h && m.actual[1] === a;
      const cls = "cell" + (isModal ? " modal" : "") + (isAct ? " actual" : "");
      cells += `<div class="${cls}" style="background:${tint(h, a, p)}"
        title="${h}-${a}: ${pct(p, 1)}">${p >= 0.04 ? Math.round(100 * p) : ""}</div>`;
    }
  }
  const wdl = `<div class="mh-wdl">
    <span style="width:${100 * m.pH}%;background:var(--accent)" title="${home} win ${pct(m.pH, 0)}"></span>
    <span style="width:${100 * m.pD}%;background:var(--muted)" title="draw ${pct(m.pD, 0)}"></span>
    <span style="width:${100 * m.pA}%;background:var(--hot)" title="${away} win ${pct(m.pA, 0)}"></span></div>`;
  // knockout: the draw can't stand — spell out how extra time + penalties split it and
  // who ends up going through the tie (same maths as the hatched slice on the fixture bar).
  const isKO = m.group === "Knockout";
  const dH = m.pD * (m.pH / (m.pH + m.pA || 1)), dA = m.pD - dH, adH = m.pH + dH;
  const advBox = isKO ? `<div class="mh-adv">
      <div class="mh-adv-t">Who goes through <span>(90 min + extra time + penalties)</span></div>
      <div class="mh-adv-row"><span>${flag(home)} ${home}</span>
        <b>${pct(adH, 0)}</b>
        <span class="mh-adv-x">${pct(m.pH, 0)} in 90′ + ${pct(dH, 0)} of the draw</span></div>
      <div class="mh-adv-row"><span>${flag(away)} ${away}</span>
        <b>${pct(1 - adH, 0)}</b>
        <span class="mh-adv-x">${pct(m.pA, 0)} in 90′ + ${pct(dA, 0)} of the draw</span></div>
    </div>` : "";
  const t = m.top[0];
  const actLine = m.actual
    ? `Actual result <b>${m.actual[0]}–${m.actual[1]}</b> (model gave it ${pct(G[Math.min(m.actual[0],5)][Math.min(m.actual[1],5)], 1)}).`
      + (isKO && m.winner ? ` ${flag(m.winner)}<b>${m.winner}</b> went through.` : "")
    : `Not played yet.`;
  ov.innerHTML = `<div class="mh-card">
    <span class="mh-close" onclick="document.getElementById('mh-overlay').classList.remove('show')">×</span>
    <h4>${flag(home)} ${home} <span style="color:var(--muted)">v</span> ${away} ${flag(away)}</h4>
    <div class="mh-sub">${[m.group && m.group !== "Knockout" ? "Group " + m.group : "Knockout", m.date, venueTag(m.city)].filter(Boolean).join(" · ")} · pre-match forecast (xG ${m.lh}–${m.la})</div>
    ${wdl}
    ${advBox}
    <div style="display:flex;gap:8px"><div class="mh-axtitle vert">${home} goals →</div>
      <div style="flex:1"><div class="mh-grid">${cells}</div>
      <div class="mh-axtitle">${away} goals →</div></div></div>
    <div class="mh-note">Most likely <b>${t.h}–${t.a}</b> (${pct(t.p, 0)}). W/D/L
      <b>${pct(m.pH, 0)}</b>/<b>${pct(m.pD, 0)}</b>/<b>${pct(m.pA, 0)}</b>. ${actLine}
      <span style="display:block;margin-top:6px;opacity:.8">Green = ${home} win, red = ${away} win, slate = draw; brighter = more likely. White ring = actual.</span></div>
  </div>`;
  ov.classList.add("show");
}

/* ---------- follow a team: its road through the tournament ---------- */
function showTeam(name) {
  const t = WC26.teams.find((x) => x.team === name);
  if (!t) return;
  let ov = $("team-overlay");
  if (!ov) {
    ov = document.createElement("div");
    ov.id = "team-overlay"; ov.className = "mh-overlay";
    document.body.appendChild(ov);
    ov.addEventListener("click", (e) => { if (e.target === ov) ov.classList.remove("show"); });
    document.addEventListener("keydown", (e) => { if (e.key === "Escape") ov.classList.remove("show"); });
  }
  const group = [["Win the group", t.P1], ["Finish 2nd", t.P2], ["Reach the knockouts", t.P_qualify]];
  const road = [["Round of 32", t.P_R32], ["Round of 16", t.P_R16], ["Quarter-final", t.P_QF],
    ["Semi-final", t.P_SF], ["Final", t.P_final], ["Champion", t.P_champion]];
  const max = Math.max(t.P_qualify, t.P_R32, 0.01);
  const row = (lab, p, gold) => `<div class="tm-row"><span class="tm-lab">${lab}</span>
    <div class="tm-track"><i style="width:${(100 * p) / max}%;${gold ? "background:var(--gold)" : ""}"></i></div>
    <span class="tm-val${gold ? " g" : ""}">${pct(p, 0)}</span></div>`;
  ov.innerHTML = `<div class="mh-card tm-card">
    <span class="mh-close" onclick="document.getElementById('team-overlay').classList.remove('show')">×</span>
    <h4>${flag(name)} ${name}</h4>
    <div class="mh-sub">Group ${t.group} · Elo ${t.elo} · its road through the tournament</div>
    <div class="tm-h">In the group</div>${group.map(([l, p]) => row(l, p)).join("")}
    <div class="tm-h">How far it goes</div>${road.map(([l, p]) => row(l, p, l === "Champion")).join("")}
    <div class="mh-note">Each bar is the chance of reaching that stage across the 20,000 simulations
      (live-conditioned on results so far). Bars shrink as the tournament narrows.</div>
  </div>`;
  ov.classList.add("show");
}

/* ---------- next matches: model vs market 1X2 (scripts/42) ---------- */
if (WC26.next_matches && WC26.next_matches.matches && $("next-board")) {
  // a match leaves this board only when its RESULT has been ingested (the data
  // refresh lands the morning after); a game that has merely kicked off stays
  // up, flagged "awaiting result", so it never vanishes into a gap.
  const playedPair = new Set();
  (WC26.bracket_dists || []).forEach((m) => { if (m.winner) { playedPair.add(m.home + "|" + m.away); playedPair.add(m.away + "|" + m.home); } });
  (WC26.match_dists || []).forEach((m) => { if (m.actual) { playedPair.add(m.home + "|" + m.away); playedPair.add(m.away + "|" + m.home); } });
  const nm = WC26.next_matches.matches.filter((m) => !playedPair.has(m.home + "|" + m.away));
  // For a knockout tie the draw doesn't stand: extra time + penalties split it in
  // proportion to each side's 90-minute win chance. We keep the same 1X2 bar but hatch
  // (zebra) the draw slice — its home-tinted / away-tinted halves so the colour change
  // lands exactly at each side's chance of going through the tie.
  const x123 = (p, ko) => {
    const seg = (w, c, lab) => w > 0.001
      ? `<span class="x-seg" style="width:${100 * w}%;background:${c}" title="${lab} ${pct(w, 0)}">${100 * w >= 15 ? Math.round(100 * w) : ""}</span>` : "";
    if (!ko) {
      return `<div class="x-bar">${seg(p.pH, "var(--accent)", "home win")}${seg(p.pD, "var(--muted)", "draw")}${seg(p.pA, "var(--hot)", "away win")}</div>`;
    }
    const hShare = p.pH / (p.pH + p.pA || 1);
    const dH = p.pD * hShare, dA = p.pD - dH;
    const adH = p.pH + dH;
    const zeb = (tint) => `repeating-linear-gradient(45deg,${tint} 0 3px,var(--muted) 3px 6px)`;
    const hatch = (w, tint, lab) => w > 0.0005
      ? `<span class="x-seg x-zeb" style="width:${100 * w}%;background:${zeb(tint)}" title="${lab}"></span>` : "";
    const tH = `draw ${pct(p.pD, 0)} split by extra time + penalties · ${pct(dH, 0)} to home → goes through ${pct(adH, 0)}`;
    const tA = `draw ${pct(p.pD, 0)} split by extra time + penalties · ${pct(dA, 0)} to away → goes through ${pct(1 - adH, 0)}`;
    return `<div class="x-bar" title="goes through the tie: home ${pct(adH, 0)} · away ${pct(1 - adH, 0)}">` +
      `${seg(p.pH, "var(--accent)", "home win")}` +
      `${hatch(dH, "var(--accent)", tH)}${hatch(dA, "var(--hot)", tA)}` +
      `${seg(p.pA, "var(--hot)", "away win")}` +
      `<span class="x-thru" style="left:${100 * adH}%"></span></div>`;
  };
  const fmt = (iso) => { try { return new Date(iso).toLocaleString("en-GB", { weekday: "short", hour: "2-digit", minute: "2-digit", timeZone: "Europe/Paris" }) + " CET"; } catch (_) { return ""; } };
  $("next-board").innerHTML = nm.map((m) => {
    const gap = Math.max(Math.abs(m.model.pH - m.market.pH), Math.abs(m.model.pA - m.market.pA), Math.abs(m.model.pD - m.market.pD));
    // flag disagreement on size OR on which side is favoured (opposite favourites can be a
    // small numeric gap yet a real disagreement, e.g. model backs the away side, market the home).
    const favOf = (p) => (p.pH >= p.pD && p.pH >= p.pA) ? "H" : (p.pA >= p.pD ? "A" : "D");
    // in a knockout what matters is WHO GOES THROUGH, so the flag fires only when
    // model and market back different advancers (a big 1X2 gap on the same side —
    // e.g. FRA-MOR 45% vs 60%, both France — is a nuance, not a disagreement).
    const advH = (p) => p.pH + p.pD * (p.pH / (p.pH + p.pA || 1));
    const flip = m.ko ? (advH(m.model) >= 0.5) !== (advH(m.market) >= 0.5)
                      : (favOf(m.model) !== favOf(m.market) || gap >= 0.10);
    const div = flip ? `<span class="nm-div" title="${m.ko ? "model and market back different sides to go through" : "model and market disagree on this match"}">model ≠ market</span>` : "";
    const stageLab = m.stage === "final" ? "🏆 The final" : m.stage === "third" ? "Third place" : (m.ko ? "Knockout" : "Group");
    return `<div class="nm-card clickable${m.stage === "final" ? " nm-final" : ""}" data-home="${m.home}" data-away="${m.away}">
      <div class="nm-head"><span class="nm-team">${flag(m.home)}${m.home}</span>
        <span class="nm-vs">${m.ko ? "⚔" : "v"}</span>
        <span class="nm-team away">${m.away}${flag(m.away)}</span></div>
      <div class="nm-meta"><span class="nm-when">${stageLab} · ${fmt(m.commence)}</span>${m.city ? `<span class="nm-venue">${venueTag(m.city)}</span>` : ""}
        ${div}<span class="mh-hint">heatmap ▸</span>
        ${new Date(m.commence).getTime() < Date.now() ? `<span class="nm-wait" title="kicked off; the score lands with the next morning's data refresh">⏳ awaiting result</span>` : ""}</div>
      <div class="nm-line"><span class="nm-lab">Model</span>${x123(m.model, m.ko)}</div>
      <div class="nm-line"><span class="nm-lab">Market</span>${x123(m.market, m.ko)}</div>
    </div>`;
  }).join("");
  $("next-board").querySelectorAll(".nm-card.clickable").forEach((c) =>
    c.addEventListener("click", () => showHeat(c.dataset.home, c.dataset.away)));
  if ($("next-note")) $("next-note").innerHTML = nm.length
    ? `<strong>${nm.length}</strong> upcoming games. Green = home team wins, slate = draw, red = away
     (90 minutes). Market = consensus of ~${nm[0].market.n_books} bookmakers, with their built-in profit
     margin taken out so it reads as a fair probability. In a knockout
     the draw slice is hatched and split by who survives extra time and penalties, so the colour change
     marks each side's chance of going through.`
    : `No upcoming fixtures with odds yet, the next refresh fills this in.`;
}

/* ---------- live status strip ---------- */
if ($("live-strip") && WC26.generated) {
  $("live-strip").insertAdjacentHTML("beforeend", ` · updated ${WC26.generated}`);
}

/* ---------- hero: giant live champion number + supporting stats ---------- */
{
  const fav = byChamp[0];
  const bt = WC26.backtest;
  const sc = WC26.scoring;
  if ($("hero-leader")) {
    // only teams still alive chase the leader (an eliminated side at 0% is noise;
    // by the final there is exactly one challenger left)
    const chase = byChamp.slice(1, 3).filter((c) => c.P_champion >= 0.001)
      .map((c) => `${flag(c.team)}${TLA3(c.team)} ${pct(c.P_champion, 0)}`).join("  ·  ");
    $("hero-leader").innerHTML = `
      <div class="hc-lab">Most likely champion</div>
      <div class="hc-flag">${flag(fav.team)}</div>
      <div class="hc-team">${fav.team}</div>
      <div class="hc-pct tnum">${(100 * fav.P_champion).toFixed(1)}<span>%</span></div>
      <div class="hc-chase">then ${chase}</div>
      ${sc && sc.n ? `<div class="hc-note">running log-loss <b>${sc.log_loss}</b> vs ${sc.uniform} · ${sc.n} games scored</div>` : ""}`;
  }
  // headline = how the frozen forecast is scoring against reality, if live
  const headline = sc && sc.n
    ? `<div class="stat headline"><div class="v">${sc.log_loss} <span class="vs">vs ${sc.uniform}</span></div>
        <div class="k">live score vs guessing, log-loss, lower is better (${sc.n} matches)</div></div>`
    : "";
  const backtestStat = `<div class="stat"><div class="v">${bt.log_loss_model} <span class="vs">vs ${bt.log_loss_uniform}</span></div>
      <div class="k">backtest log-loss (WC2022)</div></div>`;
  if ($("hero-stats")) $("hero-stats").innerHTML = `
    ${headline}
    <div class="stat"><div class="v">${WC26.n_sims.toLocaleString("en-US")}</div>
      <div class="k">simulated tournaments</div></div>
    ${backtestStat}`;
}

/* ---------- THE FORECAST: one slider drives champion + bracket + thirds + Golden Boot + groups ---------- */
if (WC26.replay && WC26.replay.snapshots && document.querySelector(".fc-bar")) {
  const snaps = WC26.replay.snapshots;
  const tg = WC26.replay.teams_group;
  const N = snaps.length - 1;        // last index; index 0 = before kickoff
  // end of the group stage; the 72-match structure is fixed, so if a refresh ever drops
  // group_end_k the marker stays put instead of drifting to the end of the slider.
  const GEK = Math.min((WC26.replay.group_end_k != null) ? WC26.replay.group_end_k : 72, N);
  let cur = N;

  // Build a rich, synced control inside every .fc-bar:
  //   ◀  [============o====]  ▶   "match 18 / 28 · 2026-06-18 · Canada 6-0 Qatar"
  const bars = [...document.querySelectorAll(".fc-bar")];
  bars.forEach((bar) => {
    bar.innerHTML =
      `<button type="button" class="fc-step fc-prev" aria-label="previous match">◀</button>` +
      `<div class="fc-track-wrap">` +
        `<input type="range" class="fc-slider" min="0" max="${N}" step="1" value="${N}" aria-label="match number">` +
        `<div class="fc-ticks"></div>` +
      `</div>` +
      `<button type="button" class="fc-step fc-next" aria-label="next match">▶</button>` +
      `<span class="fc-lab"></span>`;
    // tick notches, one per snapshot
    const ticks = bar.querySelector(".fc-ticks");
    ticks.innerHTML = snaps.map((_, i) =>
      `<i class="${i === GEK ? "grp-end" : ""}" style="left:${N ? (100 * i) / N : 0}%"></i>`).join("") +
      (GEK > 0 && GEK < N ? `<span class="grp-marker" style="left:${(100 * GEK) / N}%" title="group stage ends here, knockouts after this point">⚑<em> groups end</em></span>` : "");
  });
  const sliders = [...document.querySelectorAll(".fc-slider")];
  const labs = [...document.querySelectorAll(".fc-lab")];

  const delta = (now, was, dp = 1) => {
    if (was === undefined || was === null) return "";
    const d = now - was;
    if (Math.abs(d) < 0.005) return "";
    return `<span class="delta ${d > 0 ? "up" : "down"}">${d > 0 ? "▲" : "▼"}${(100 * Math.abs(d)).toFixed(dp)}</span>`;
  };
  const TLA = (t) => ({
    "United States": "USA", "South Korea": "KOR", "South Africa": "RSA", "Saudi Arabia": "KSA",
    "Czech Republic": "CZE", "Bosnia and Herzegovina": "BIH", "Ivory Coast": "CIV",
    "DR Congo": "COD", "Cape Verde": "CPV", "New Zealand": "NZL", "Netherlands": "NED",
  }[t] || (t || "?").slice(0, 3).toUpperCase());
  // "Uruguay 2-2 Cape Verde" -> "🇺🇾 URU 2–2 CPV 🇨🇻" (flags + 3-letter codes; compact,
  // so the fixed-width slider label never has to truncate a long country name)
  const shortMatch = (str) => {
    const m = /^(.+?) (\d+)\s*[-–]\s*(\d+) (.+)$/.exec(str || "");
    return m ? `${flag(m[1])}${TLA(m[1])} ${m[2]}–${m[3]} ${TLA(m[4])}${flag(m[4])}` : str;
  };
  const COLS = [
    ["Round of 32", [74, 77, 73, 75, 83, 84, 81, 82, 76, 78, 79, 80, 86, 88, 85, 87]],
    ["Round of 16", [89, 90, 93, 94, 91, 92, 95, 96]],
    ["Quarter-finals", [97, 98, 99, 100]],
    ["Semi-finals", [101, 102]],
    ["Final", [104]],
  ];
  // --- custom "climb to the trophy" bracket + pick-the-winner sandbox ---
  // which two matches feed each later match (top feeder, bottom feeder)
  const FEED = { 89: [74, 77], 90: [73, 75], 91: [76, 78], 92: [79, 80], 93: [83, 84],
    94: [81, 82], 95: [86, 88], 96: [85, 87], 97: [89, 90], 98: [93, 94], 99: [91, 92],
    100: [95, 96], 101: [97, 98], 102: [99, 100], 104: [101, 102] };
  // real results already in: matchNum -> the team that actually went through. Played ties
  // are fixed to reality in the bracket (and can't be re-picked in the sandbox).
  const KOW = {}; (WC26.bracket_dists || []).forEach((m) => { if (m.winner) KOW[m.match] = m.winner; });
  // the CHRONOLOGICAL order the knockout ties were actually played in, read off the
  // replay's own per-match labels: match numbers are NOT chronological (m76 was played
  // before m74), so pinning "first koPlayedN by number" ticked the wrong ties mid-round.
  const PAIR2MN = {}; (WC26.bracket_dists || []).forEach((m) => {
    PAIR2MN[m.home + "|" + m.away] = m.match; PAIR2MN[m.away + "|" + m.home] = m.match; });
  const KO_ORDER = [];
  for (let i = GEK + 1; i < snaps.length; i++) {
    const mm = (snaps[i].last_match || "").match(/^(.+?) \d+-\d+ (.+)$/);
    const mn = mm && PAIR2MN[mm[1] + "|" + mm[2]];
    if (mn != null) KO_ORDER.push(mn);
  }
  // order every round by the FEED tree (DFS from the final) so each tie sits directly
  // beside the two ties that feed it, the columns then read like a classic bracket.
  const parentOf = {}; Object.entries(FEED).forEach(([p, ch]) => ch.forEach((c) => (parentOf[c] = +p)));
  const dfs = (n) => FEED[n] ? [...dfs(FEED[n][0]), ...dfs(FEED[n][1])] : [n];
  const nextRound = (prev) => { const o = []; for (let i = 0; i < prev.length; i += 2) o.push(parentOf[prev[i]]); return o; };
  // split the tree into two halves that mirror around the final (classic TV bracket):
  // the left half feeds semi-final 101, the right half feeds 102; they meet in the centre.
  const half = (root) => { const a = dfs(root), b = nextRound(a), c = nextRound(b), d = nextRound(c); return [a, b, c, d]; };
  const HALF_L = half(101), HALF_R = half(102);
  const RLAB = ["R32", "R16", "QF", "SF"];
  const ELO = {}; WC26.teams.forEach((t) => { ELO[t.team] = t.elo; });
  const eloP = (a, b) => 1 / (1 + Math.pow(10, -(((ELO[a] || 1500) - (ELO[b] || 1500)) / 400)));
  const modalShare = (m) => {  // head-to-head share of the top slot (sums to 1 with bot)
    const cT = m && m.top && m.top.p > 0 ? (m.top.adv || 0) / m.top.p : 0;
    const cB = m && m.bot && m.bot.p > 0 ? (m.bot.adv || 0) / m.bot.p : 0;
    const z = cT + cB; return z > 0 ? cT / z : 0.5;
  };
  const picks = {};  // matchNum -> chosen winner (sandbox); cleared by Reset
  let sandbox = false;
  let bracketMode = "reach";  // "reach" = P(team fills this slot) | "adv" = win-the-tie share
  // "Win the tie" = the head-to-head SHARE between the two named teams: each side's
  // conditional win-if-here (adv/p) normalised so the two slots of a match sum to 100%.
  // Reads as "who wins this match", two strong finalists land ~50/50, a favourite high.
  const slotHTML = (s, disp) => {
    if (!s) return `<div class="bk-slot"><span class="bk-team">-</span></div>`;
    const v = bracketMode === "adv" ? (disp ?? 0) : s.p;
    const cls = v >= 0.6 ? "sure" : v < 0.3 ? "open" : "";
    const title = bracketMode === "adv"
      ? `${s.team}: wins this tie ${pct(v, 0)} of the time when it meets the team in the other slot (reaches the slot ${pct(s.p, 0)})`
      : `${s.team}: ${pct(s.p, 0)} chance of filling this slot`;
    return `<div class="bk-slot ${cls}" title="${title}"><span class="bk-team">${flag(s.team)}${TLA(s.team)}</span><span class="bk-p">${pct(v, 0)}</span></div>`;
  };
  // per-match win-the-tie shares (normalised conditional), or [null,null] in reach mode
  const tieShares = (m) => {
    if (bracketMode !== "adv" || !m.top || !m.bot) return [null, null];
    const cT = m.top.p > 0 ? (m.top.adv ?? 0) / m.top.p : 0;
    const cB = m.bot.p > 0 ? (m.bot.adv ?? 0) / m.bot.p : 0;
    const s = cT + cB;
    return s > 0 ? [cT / s, cB / s] : [0, 0];
  };

  const setLegend = () => {
    if (!$("bracket-legend")) return;
    $("bracket-legend").innerHTML = sandbox
      ? `<strong>Sandbox:</strong> tap a team to send it through, the bracket rebuilds your way, all the
         way to the trophy. Every match-up, even one only you predicted, is priced by the same goal
         model. Tap <em>the bar</em> for a tie's expected-goals heatmap. <em>Reset</em> returns to the model.`
      : `The two halves <strong>climb to the trophy</strong>. Each tie is a <strong>tug-of-war</strong> -
         the bar shows the <strong>head-to-head, who wins the tie</strong> (the two add up to 100%). The
         winning side is green. Tap a tie for its <strong>expected-goals heatmap</strong>, or switch to
         <em>Sandbox</em> to build your own bracket.`;
  };
  setLegend();

  const render = (k) => {
    cur = k;
    const s = snaps[k], prev = k > 0 ? snaps[k - 1] : null;
    sliders.forEach((sl) => { if (+sl.value !== k) sl.value = k; });
    const counter = k === 0 ? "before kickoff" : `match ${k} / ${N}`;
    const detail = k === 0 ? `${s.date} · before any result` : `${s.date} · ${shortMatch(s.last_match)}`;
    labs.forEach((l) => { l.innerHTML = `<b>${counter}</b><span class="fc-lab-detail">${detail}</span>`; });
    document.querySelectorAll(".fc-prev").forEach((b) => (b.disabled = k <= 0));
    document.querySelectorAll(".fc-next").forEach((b) => (b.disabled = k >= N));

    // champion ordering, kept for the bracket apex/legend below
    const top = Object.entries(s.champion).sort((a, b) => b[1] - a[1]).slice(0, 12);
    // round by round: P(reach each stage) for EVERY team, driven by the slider. This
    // replaces the flat champion list, same title odds in the last column, but the
    // whole road to it, and it keeps moving through the knockouts.
    if ($("fc-rounds") && s.rounds) {
      const RH = ["R32", "R16", "QF", "SF", "Final", "Champ"];
      const heatc = (p) => { const a = Math.min(0.85, p * 1.15); return `background: rgba(74, 222, 128, ${a.toFixed(3)}); color: ${a > 0.45 ? "#07101f" : "var(--text)"}`; };
      // deepest run first: compare champion odds, then final, SF, QF, R16, R32 —
      // sorting on the title column alone collapses once eliminations set most
      // teams to 0 and the tail ordering turns arbitrary. Alphabetical tie-break.
      const rr = Object.entries(s.rounds).sort((a, b) => {
        for (let i = 5; i >= 0; i--) { const d = b[1][i] - a[1][i]; if (Math.abs(d) > 1e-9) return d; }
        return a[0] < b[0] ? -1 : 1;
      });
      $("fc-rounds").innerHTML =
        `<thead><tr><th>Team</th>${RH.map((h) => `<th>${h}</th>`).join("")}</tr></thead><tbody>` +
        rr.map(([t, v]) => { const pr = prev && prev.rounds ? prev.rounds[t] : null;
          return `<tr><td class="tm-click" data-team="${t}" title="click for ${t}'s road">${flag(t)}${TLA3(t)}</td>` +
          v.map((p, i) => `<td class="heat" style="${heatc(p)}">${p >= 0.005 ? pct(p, 0) : ""}${(i === 5 && pr) ? delta(p, pr[5], 0) : ""}</td>`).join("") + `</tr>`; }).join("") +
        `</tbody>`;
      $("fc-rounds").querySelectorAll(".tm-click").forEach((c) => c.addEventListener("click", () => showTeam(c.dataset.team)));
    }

    // custom bracket: each tie is a head-to-head "tug of war"; the two halves climb
    // to the trophy. Sandbox picks override the model winner and rebuild downstream.
    const part = {}, win = {}, share = {};
    // Sandbox follows the slider like the model view. The snapshot bracket is a
    // CONSISTENT tree (32 distinct predicted qualifiers even mid-groups, built
    // pipeline-side), so picks are safe at any point in time: scrubbing back
    // unpins results that hadn't happened yet and those ties become re-pickable
    // what-ifs from that moment on.
    const bsrc = s;
    // only pin knockout ties that had been played by THIS slider position, so scrubbing
    // back doesn't show ✓ ticks (or locked teams) for results that hadn't happened yet.
    const koPlayedN = Math.max(0, k - GEK);
    const KOWk = {};
    (KO_ORDER.length ? KO_ORDER : Object.keys(KOW).map(Number).sort((x, y) => x - y))
      .slice(0, koPlayedN).forEach((mn) => { if (KOW[mn]) KOWk[mn] = KOW[mn]; });
    // a slot is "in play" once the user has picked somewhere in the ties that feed it; until
    // then even the sandbox shows the model's most-likely occupant, so an untouched sandbox
    // mirrors the model bracket exactly (every tie keeps its precomputed heatmap and stays
    // clickable). Only picks ripple a divergent pairing forward.
    const touched = (n) => picks[n] != null || (FEED[n] && (touched(FEED[n][0]) || touched(FEED[n][1])));
    [73, 74, 75, 76, 77, 78, 79, 80, 81, 82, 83, 84, 85, 86, 87, 88,
     89, 90, 91, 92, 93, 94, 95, 96, 97, 98, 99, 100, 101, 102, 104].forEach((mn) => {
      const modal = bsrc.bracket && bsrc.bracket[mn];
      // model view: fill each slot with its most-likely occupant (the marginal), so the
      // final pits the two most-likely finalists. sandbox: once a feeding tie is picked,
      // propagate winners up the FEED tree so the user's picks ripple forward.
      const fromModal = !(sandbox && FEED[mn] && touched(mn));
      if (!fromModal) part[mn] = { top: win[FEED[mn][0]], bot: win[FEED[mn][1]] };
      else part[mn] = { top: modal && modal.top && modal.top.team, bot: modal && modal.bot && modal.bot.team };
      const a = part[mn].top, b2 = part[mn].bot;
      if (!a || !b2) { win[mn] = a || b2; share[mn] = 1; return; }
      if (KOWk[mn] && (KOWk[mn] === a || KOWk[mn] === b2)) {
        // this tie has been played by now, pin it to the real result (100%), no re-picking.
        win[mn] = KOWk[mn];
        share[mn] = (KOWk[mn] === a) ? 1 : 0;
      } else {
        // the bar is "who goes through if they meet": the venue-aware goal model,
        // computed client-side with the same formula the pipeline uses to propagate
        // winners — deterministic (no Monte Carlo wobble across slider positions)
        // and consistent by construction with the next round's occupant.
        const hh = tieShare(a, b2, mn);
        share[mn] = hh != null ? hh : eloP(a, b2);
        win[mn] = (picks[mn] === a || picks[mn] === b2) ? picks[mn] : (share[mn] >= 0.5 ? a : b2);
      }
    });
    const champTeam = win[104];
    const champShare = part[104] && part[104].top === champTeam ? share[104] : 1 - share[104];
    // probability the ENTIRE drawn bracket plays out exactly like this, the chain of every
    // tie's head-to-head, including matches that don't touch the champion (they're still part
    // of the same drawn bracket).
    let bracketProb = 1;
    Object.keys(part).forEach((k) => {
      const mn = +k;
      if (part[mn].top && part[mn].bot) bracketProb *= (win[mn] === part[mn].top ? share[mn] : 1 - share[mn]);
    });
    const oneIn = (n) => n >= 1e9 ? (n / 1e9).toFixed(1) + " billion" : n >= 1e6 ? (n / 1e6).toFixed(1) + " million" : n >= 1e3 ? Math.round(n / 1e3) + "k" : Math.round(n);
    const fmtProb = (p) => p >= 0.01 ? pct(p, 1) : "1 in " + oneIn(Math.round(1 / p));
    const card = (mn) => {
      const a = part[mn].top, b = part[mn].bot;
      if (!a || !b) return `<div class="tie empty">-</div>`;
      const pa = share[mn], w = win[mn], played = KOWk[mn] != null;
      const heat = MD[a + "|" + b] ? [a, b] : (MD[b + "|" + a] ? [b, a] : (getDist(a, b, mn) ? [a, b] : null));
      // played ties are locked to the real result; only future ties are pickable in sandbox
      const side = (t, p, hi) => `<div class="tie-side ${w === t ? "win" : ""}${sandbox && !played ? " pickable" : ""}" data-pick="${t}">
        <span class="ts-team">${flag(t)}${TLA(t)}</span><span class="ts-p">${played ? (w === t ? "✓" : "") : pct(p, 0)}</span></div>`;
      return `<div class="tie${picks[mn] ? " picked" : ""}${played ? " played" : ""}${heat ? " has-heat" : ""}" data-m="${mn}"${heat ? ` data-home="${heat[0]}" data-away="${heat[1]}"` : ""}>
        ${side(a, pa)}
        <div class="tow" title="head-to-head, who wins the tie">${heat ? '<span class="tow-heat">⊞</span>' : ""}<i class="a" style="width:${100 * pa}%"></i><i class="b" style="width:${100 * (1 - pa)}%"></i></div>
        ${side(b, 1 - pa)}</div>`;
    };
    const apex = `<div class="bk-apex"><div class="bk-trophy">🏆</div>
      <div class="bk-champ">${flag(champTeam)}${champTeam}${!sandbox ? ` <b>${pct(champShare, 0)}</b>` : ""}</div>
      <div class="bk-champ-lab">${sandbox ? "your champion" : "wins the most-likely final"}</div>
      <div class="bk-bprob" title="chance this entire bracket plays out exactly as drawn, every tie chained together">${sandbox ? "your" : "modal"} bracket happens: <b>${fmtProb(bracketProb)}</b></div></div>`;
    const col = (lab, nums, side) => `<div class="bk-col bk-${side}"><div class="bk-rlab">${lab}</div><div class="ties">${nums.map(card).join("")}</div></div>`;
    const leftHTML = HALF_L.map((nums, i) => col(RLAB[i], nums, "l")).join("");
    // right half rendered centre → edge, so SF sits next to the final and R32 at the far right
    const rightHTML = HALF_R.slice().reverse().map((nums, i) => col(RLAB[RLAB.length - 1 - i], nums, "r")).join("");
    const centre = `<div class="bk-col bk-centre"><div class="bk-rlab">Final</div><div class="ties">${card(104)}</div>${apex}</div>`;
    $("fc-bracket").innerHTML = leftHTML + centre + rightHTML;

    // why the bracket champion can differ from round-by-round's most-likely champion:
    // the bracket follows the favourite through every tie (one modal path), while
    // round-by-round integrates ALL paths. A team can win the modal final yet be less
    // likely to lift the cup overall because its road there is harder.
    if ($("bracket-why")) {
      if (sandbox) {
        $("bracket-why").innerHTML = `Sandbox: your picks override the model, tap a team to send it through, ↺ to reset.`;
      } else {
        const margTeam = top[0][0], margPct = pct(top[0][1], 0);
        let sfOpp = null;
        for (const sf of [101, 102]) if (win[sf] === champTeam && part[sf]) sfOpp = part[sf].top === champTeam ? part[sf].bot : part[sf].top;
        $("bracket-why").innerHTML = (champTeam === margTeam)
          ? `Put the two most-likely finalists head-to-head and <strong>${flag(champTeam)}${champTeam}</strong> takes it (${pct(champShare, 0)}), the same team round-by-round makes the single most-likely champion (${margPct}). The two views agree.`
          : `The bracket fills each slot with its <strong>most-likely occupant</strong>, so the final is the two likeliest finalists, and <strong>${flag(champTeam)}${champTeam}</strong> edges it <strong>${pct(champShare, 0)}–${pct(1 - champShare, 0)}</strong>. Round by round, though, the most likely champion <em>overall</em> is <strong>${flag(margTeam)}${margTeam}</strong> (${margPct}). No contradiction: ${champTeam} is favoured in that final but has the <strong>harder road to reach it</strong>${sfOpp ? `, past <strong>${flag(sfOpp)}${sfOpp}</strong> in the semi` : ""}, so across <em>all</em> paths ${margTeam} lifts the cup more often.`;
      }
    }

    // groups & best thirds are group-stage facts, freeze them once the group stage is
    // over; the bracket, round-by-round and Golden Boot keep moving through the knockouts.
    // groups freeze at GEK; past it, drop the ▲▼ badges too — they'd forever
    // replay the last matchday's moves (DR Congo's ▲ stuck on screen for weeks).
    const gk = Math.min(k, GEK), sg = snaps[gk], sgPrev = (gk > 0 && k <= GEK) ? snaps[gk - 1] : null;
    // best thirds (8 of 12 advance), ranked by P(advance as a best third)
    const th = Object.entries(sg.best_third || {}).filter(([, p]) => p > 0.01)
      .sort((a, b) => b[1] - a[1]).slice(0, 12);
    const tmax = th[0] ? th[0][1] : 1;
    $("fc-thirds").innerHTML = th.map(([t, p], i) => `
      ${i === 8 ? '<div class="cutoff">- 8 advance -</div>' : ""}
      <div class="bar-row">
        <div class="who">${flag(t)}${t}</div>
        <div class="bar-track"><div class="bar-fill" style="width:${(100 * p) / tmax}%;${i < 8 ? "" : "opacity:.5"}"></div></div>
        <div class="val">${pct(p, 0)}${delta(p, sgPrev && sgPrev.best_third && sgPrev.best_third[t], 0)}</div>
      </div>`).join("");

    // golden boot; drop the dead tail (eliminated / out-scored players whose
    // conditioned chance has collapsed to ~zero) so late-tournament lists don't
    // fill up with 0.0% rows. Harmless early on: nobody starts below 0.1%.
    const gb = (s.golden_boot || []).filter((x) => x.p >= 0.001);
    const pgb = {}; (prev && prev.golden_boot || []).forEach((x) => (pgb[x.player] = x.p));
    const gmax = gb[0] ? gb[0].p : 1;
    $("fc-gb").innerHTML = gb.slice(0, 10).map((p) => `
      <div class="bar-row">
        <div class="who">${flag(p.team)}${p.player}${p.e != null ? `<span class="gb-goals"><b>${p.g ?? 0}</b> scored · <b>${p.e.toFixed(1)}</b> expected at the end</span>` : ""}</div>
        <div class="bar-track"><div class="bar-fill" style="width:${(100 * p.p) / gmax}%"></div></div>
        <div class="val">${pct(p.p)}${delta(p.p, prev && pgb[p.player])}</div>
      </div>`).join("");

    // groups, probability of advancing
    const groups = {};
    Object.entries(tg).forEach(([t, g]) => (groups[g] = groups[g] || []).push(t));
    $("fc-groups").innerHTML = Object.keys(groups).sort().map((g) => {
      // order by advance probability; ties (e.g. everyone decided at 100%/0%)
      // break on the group's real final standing, so the winner tops the card.
      const stdIdx = {};
      ((WC26.standings || {})[g] || []).forEach((r, i) => { stdIdx[r.team] = i; });
      const ranked = groups[g].map((t) => [t, sg.qualify[t] ?? 0])
        .sort((a, b) => (b[1] - a[1]) || ((stdIdx[a[0]] ?? 9) - (stdIdx[b[0]] ?? 9)));
      // "tight" is specifically about WHO ADVANCES (not who finishes 1st): two or more
      // teams genuinely on the bubble for a knockout place (advance prob between 25-75%).
      const bubble = ranked.filter(([, q]) => q > 0.25 && q < 0.75);
      const tight = bubble.length >= 2;
      const names = bubble.map(([t, q]) => `${t} ${pct(q, 0)}`).join(", ");
      const badge = tight
        ? `<span class="tight-badge" title="Still up for grabs, ${bubble.length} teams level for a knockout place: ${names}">⚖ qualification open</span>`
        : "";
      const rows = ranked.map(([t, q]) => `
        <div class="team-row">
          <div><div class="who">${flag(t)}${t}</div>
            <div class="qbar"><i style="width:${100 * q}%"></i></div></div>
          <div class="val"><b>${pct(q, 0)}</b>${delta(q, sgPrev && sgPrev.qualify[t], 0)}</div>
        </div>`).join("");
      return `<div class="group-card ${tight ? "tight" : ""}"><h3>GROUP ${g}${badge}</h3>${rows}</div>`;
    }).join("");
    // the model-vs-market comparison rides the same clock: our title-odds journey
    // (at this match) against the live market line.
    if (typeof renderMarket === "function") renderMarket(s.champion, k >= N ? null : s.date);
  };
  const go = (k) => render(Math.max(0, Math.min(N, k)));
  // bracket Model / Sandbox toggle + reset
  if ($("bk-toggle")) {
    $("bk-toggle").querySelectorAll("button").forEach((b) =>
      b.addEventListener("click", () => {
        if (b.dataset.act === "reset") { for (const k in picks) delete picks[k]; render(cur); return; }
        sandbox = b.dataset.mode === "sandbox";
        $("bk-toggle").querySelectorAll("button[data-mode]").forEach((x) => x.classList.toggle("on", x === b));
        setLegend();
        render(cur);
      }));
  }
  sliders.forEach((sl) => sl.addEventListener("input", (e) => go(+e.target.value)));
  document.querySelectorAll(".fc-prev").forEach((b) => b.addEventListener("click", () => go(cur - 1)));
  document.querySelectorAll(".fc-next").forEach((b) => b.addEventListener("click", () => go(cur + 1)));
  // arrow-key stepping when a slider is focused
  sliders.forEach((sl) => sl.addEventListener("keydown", (e) => {
    if (e.key === "ArrowLeft" || e.key === "ArrowDown") { e.preventDefault(); go(cur - 1); }
    else if (e.key === "ArrowRight" || e.key === "ArrowUp") { e.preventDefault(); go(cur + 1); }
    else if (e.key === "Home") { e.preventDefault(); go(0); }
    else if (e.key === "End") { e.preventDefault(); go(N); }
  }));
  render(N);

  // bracket clicks (delegated; survive re-render): in sandbox, tapping a team
  // sends it through; otherwise tapping a tie opens its expected-goals heatmap.
  if ($("fc-bracket")) {
    $("fc-bracket").addEventListener("click", (e) => {
      const tie = e.target.closest(".tie");
      if (!tie) return;
      const side = e.target.closest(".tie-side");
      if (sandbox && side && side.dataset.pick && !tie.classList.contains("played")) {
        picks[+tie.dataset.m] = side.dataset.pick;
        render(cur);
      } else if (tie.dataset.home) {
        showHeat(tie.dataset.home, tie.dataset.away);
      }
    });
  }

  // One-time demo on load: briefly replay the last few matches so the page
  // visibly *moves* (demonstrating it's live), then settle on today. Skipped
  // for prefers-reduced-motion, and cancelled the moment the user takes over.
  (function autoplay() {
    if (N < 3) return;
    if (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;
    let k = Math.max(0, N - 6), timer = null;
    const stop = () => { if (timer) { clearTimeout(timer); timer = null; } };
    const tick = () => {
      if (k > N) { stop(); return; }
      go(k++); timer = setTimeout(tick, 430);
    };
    ["pointerdown", "keydown"].forEach((ev) =>
      document.addEventListener(ev, stop, { once: true, capture: true }));
    timer = setTimeout(tick, 800);
  })();
}

/* ---------- round-by-round table ---------- */
if ($("rounds-table")) {
  const cols = [["P_R32", "R32"], ["P_R16", "R16"], ["P_QF", "QF"], ["P_SF", "SF"], ["P_final", "Final"], ["P_champion", "Champion"]];
  const heat = (p) => {
    const a = Math.min(0.85, p * 1.15);
    return `background: rgba(74, 222, 128, ${a.toFixed(3)}); color: ${a > 0.45 ? "#07101f" : "var(--text)"}`;
  };
  $("rounds-table").innerHTML =
    `<thead><tr><th>Team</th><th>Group</th><th>Elo</th>${cols.map(([, h]) => `<th>${h}</th>`).join("")}</tr></thead>` +
    "<tbody>" + byChamp.slice(0, 16).map((t) => `
      <tr><td class="tm-click" data-team="${t.team}" title="click for ${t.team}'s road">${flag(t.team)}${t.team}</td><td>${t.group}</td><td>${t.elo}</td>
      ${cols.map(([c]) => `<td class="heat" style="${heat(t[c])}">${pct(t[c])}</td>`).join("")}</tr>`).join("") + "</tbody>";
  $("rounds-table").querySelectorAll(".tm-click").forEach((c) =>
    c.addEventListener("click", () => showTeam(c.dataset.team)));
}

/* ---------- what's earning each team its place (scripts/38) ---------- */
if (WC26.team_drivers && $("drivers-board")) {
  const ds = WC26.team_drivers.teams;
  const max = Math.max(...ds.map((d) => d.total));
  // bars are stacked: strength + max(draw,0) + max(tilt,0); negative draw/tilt
  // (group of death / fatigue) shown as a hatched "drag" segment to the left edge.
  const seg = (w, cls, title) => w > 0.0005
    ? `<div class="dr-seg ${cls}" style="width:${(100 * w) / max}%" title="${title}">${(100 * w) / max > 8 ? Math.round(100 * w) : ""}</div>` : "";
  $("drivers-board").innerHTML = ds.map((d) => {
    const dragDraw = d.draw < 0 ? -d.draw : 0, dragTilt = d.tilt < 0 ? -d.tilt : 0;
    const drag = dragDraw + dragTilt;
    return `<div class="dr-row">
      <div class="who">${flag(d.team)}${d.team}</div>
      <div class="dr-bar">
        ${seg(d.strength, "strength", `squad quality ${pct(d.strength, 0)} (avg group)`)}
        ${seg(Math.max(d.draw, 0), "draw", `easier-than-average group +${pct(d.draw, 0)}`)}
        ${seg(Math.max(d.tilt, 0), "tilt", `venue (altitude/fatigue) +${pct(d.tilt, 0)}`)}
        ${drag ? `<div class="dr-seg drag" style="width:${(100 * drag) / max}%"
          title="${dragDraw ? "tough group −" + pct(dragDraw, 0) : ""}${dragTilt ? " venue −" + pct(dragTilt, 0) : ""}"></div>` : ""}
      </div>
      <div class="val"><b>${pct(d.total, 0)}</b></div>
    </div>`;
  }).join("");
  if ($("drivers-note")) {
    const byDraw = [...ds].sort((a, b) => b.draw - a.draw)[0];
    const byTilt = [...ds].sort((a, b) => b.tilt - a.tilt)[0];
    $("drivers-note").innerHTML =
      `Most carried by the draw: <strong>${flag(byDraw.team)}${byDraw.team}</strong> ` +
      `(+${pct(byDraw.draw, 0)} from an easy group on just ${pct(byDraw.strength, 0)} squad quality). ` +
      `Most helped by venue &amp; freshness: <strong>${flag(byTilt.team)}${byTilt.team}</strong> (+${pct(byTilt.tilt, 0)}). ` +
      `Field-average Elo ${WC26.team_drivers.field_mean_elo}.`;
  }
}

/* ---------- model vs market, live odds, with movement since the eve ---------- */
// Slider-driven: the model side is P(champion) at the current slider snapshot; the
// market side is the LIVE de-vigged outright (or the frozen 11-Jun BetMGM line as a
// fallback). champMap = {team: P_champion} for the chosen snapshot, null = current.
function renderMarket(champMap, asofDate) {
  if (!$("market-chart")) return;
  // The market line follows the slider too: use the odds snapshot closest to
  // (not after) the slider's date, so scrubbing back shows the teams that were
  // STILL ALIVE then, with the prices of that day — bookmakers delist eliminated
  // nations, so filtering on today's board would erase history.
  const liveMkt = (WC26.market_now && WC26.market_now.outright) || WC26.betmgm_shin || {};
  let mkt = liveMkt;
  if (asofDate && WC26.market_hist && WC26.market_hist.length) {
    const upto = WC26.market_hist.filter((h) => h.t.slice(0, 10) <= asofDate);
    mkt = upto.length ? upto[upto.length - 1].o : (WC26.betmgm_shin || {});
  }
  const mktEve = WC26.betmgm_shin || {};   // market on the tournament eve (11 Jun)
  const modEve = WC26.baseline_eve || {};  // our own baseline on the eve (11 Jun)
  const modelP = (t) => (champMap && champMap[t.team] != null) ? champMap[t.team] : t.P_champion;
  const rows = WC26.teams
    .filter((t) => modelP(t) >= 0.001 || (mkt[t.team] || 0) >= 0.001)
    .map((t) => { const m = modelP(t); return {
      team: t.team, model: m, market: mkt[t.team] != null ? mkt[t.team] : null,
      gap: mkt[t.team] != null ? m - mkt[t.team] : 0,
      dModel: modEve[t.team] != null ? m - modEve[t.team].P_champion : null,
      dMarket: mktEve[t.team] != null && mkt[t.team] != null ? mkt[t.team] - mktEve[t.team] : null,
    }; })
    .sort((a, b) => b.model - a.model)
    .slice(0, 20);
  const max = Math.max(...rows.flatMap((r) => [r.model, r.market || 0]));
  // flag a divergence when the model and market disagree by >= 5 percentage points
  const BIG = 0.05;
  const gapChip = (g) => {
    if (Math.abs(g) < BIG) return "";
    const dir = g > 0 ? "over" : "under"; // model higher / lower than market
    return `<span class="gap-chip ${dir}" title="model ${g > 0 ? "above" : "below"} market by ${(100 * Math.abs(g)).toFixed(0)}pp">
      ${g > 0 ? "▲" : "▼"}${(100 * Math.abs(g)).toFixed(0)}pp vs market</span>`;
  };
  // movement since the eve: how this number has drifted since 11 Jun
  const mv = (d) => {
    if (d == null || Math.abs(d) < 0.005) return "";
    const up = d > 0;
    return `<span class="mv ${up ? "up" : "dn"}" title="${up ? "up" : "down"} ${(100 * Math.abs(d)).toFixed(0)}pp since the tournament started">${up ? "▲" : "▼"}${(100 * Math.abs(d)).toFixed(0)}</span>`;
  };
  $("market-chart").innerHTML = rows.map((r) => `
    <div class="pair-row ${Math.abs(r.gap) >= BIG ? "diverge" : ""}">
      <div class="who">${flag(r.team)}${r.team}${gapChip(r.gap)}</div>
      <div class="pair-bars">
        <div class="pair-bar"><div class="pair-track"><div class="pair-fill model" style="width:${(100 * r.model) / max}%"></div></div>
          <div class="pair-label">model ${pct(r.model)} ${mv(r.dModel)}</div></div>
        <div class="pair-bar"><div class="pair-track"><div class="pair-fill market" style="width:${(100 * (r.market || 0)) / max}%"></div></div>
          <div class="pair-label">${r.market != null ? `market ${pct(r.market)} ${mv(r.dMarket)}` : `<span title="no archived market quote for this date">market —</span>`}</div></div>
      </div>
    </div>`).join("");
  // headline the two sharpest disagreements
  const sharp = [...rows].sort((a, b) => Math.abs(b.gap) - Math.abs(a.gap)).slice(0, 2);
  if ($("market-diverge")) {
    const when = liveMkt
      ? `Live market, ${new Date(WC26.market_now.fetched).toLocaleDateString(undefined, { month: "short", day: "numeric" })}, ${rows.length} contenders, the bookmakers' built-in margin taken out (▲▼ = move since the tournament started). `
      : "";
    $("market-diverge").innerHTML = when + "Sharpest disagreements: " + sharp.map((r) =>
      `<strong>${flag(r.team)}${r.team}</strong> ${r.gap > 0 ? "model loves" : "model cold"} ` +
      `(${pct(r.model, 0)} vs market ${pct(r.market, 0)})`).join(" · ") + ".";
  }
  if ($("klement-note")) $("klement-note").textContent = WC26.klement;
}
renderMarket(null);

/* ---------- reality check: the frozen June-11 forecast vs what happened ---------- */
if (WC26.replay && WC26.replay.snapshots && WC26.standings && $("rc-groups")) {
  const eve = WC26.replay.snapshots[0];
  const st = WC26.standings;
  const directQual = new Set(); const thirdsRows = [];
  Object.keys(st).forEach((g) => {
    const r = st[g];
    if (r[0]) directQual.add(r[0].team);
    if (r[1]) directQual.add(r[1].team);
    if (r[2]) thirdsRows.push(r[2]);
  });
  thirdsRows.sort((a, b) => (b.Pts - a.Pts) || (b.GD - a.GD));
  const bestThirds = new Set(thirdsRows.slice(0, 8).map((r) => r.team));
  const qualified = new Set([...directQual, ...bestThirds]);
  const eq = (t) => (eve.qualify && eve.qualify[t] != null) ? eve.qualify[t] : 0;
  // What we PREDICTED would go through: the two strongest of each group (by our eve qualify
  // odds) as direct qualifiers, plus the eight teams we rated most likely to sneak in as a
  // best third. A flat >=50% is wrong, with best-third routes it calls all four in a tight
  // group, but only ~2-3 actually advance.
  // What we PREDICTED for each team: 1st or 2nd of its group (ranked by eve P1, which
  // splits the group winner from the runner-up), or one of the eight best thirds, those
  // are the "through" calls. Everyone else: out. (A flat >=50% qualify is wrong: with
  // best-third routes it calls all four in a tight group, but only ~2-3 advance.)
  const p1 = (t) => (WC26.baseline_eve && WC26.baseline_eve[t] && WC26.baseline_eve[t].P1 != null) ? WC26.baseline_eve[t].P1 : eq(t);
  const predType = {}, bubble = new Set();
  Object.keys(st).forEach((g) => {
    const ranked = st[g].map((r) => r.team).sort((a, b) => p1(b) - p1(a));
    if (ranked[0]) predType[ranked[0]] = "1st";
    if (ranked[1]) { predType[ranked[1]] = "2nd"; bubble.add(ranked[1]); }  // runner-up, on the bubble
    if (ranked[2]) bubble.add(ranked[2]);                                    // first one out, on the bubble
  });
  Object.entries(eve.best_third || {}).sort((a, b) => b[1] - a[1]).slice(0, 8).forEach(([t]) => { if (!predType[t]) predType[t] = "3rd"; });
  const predThrough = new Set(Object.keys(predType));
  // the market's own call set: Kalshi pre-kickoff prices, top 32 by price (see gc-mkt note)
  const KQ = WC26.kalshi_qualify || null;
  const mktThrough = KQ ? new Set(Object.entries(KQ).sort((x, y) => y[1] - x[1]).slice(0, 32).map(([t]) => t)) : null;
  // every qualification call, group by group: right when our prediction matched reality.
  let correct = 0, total = 0, mktCorrect = 0;
  const grpHTML = Object.keys(st).sort().map((g) => {
    let gh = 0;
    const rows = st[g].map((r) => {
      const t = r.team, pred = predThrough.has(t), act = qualified.has(t), ok = pred === act;
      total++; if (ok) { correct++; gh++; }
      if (mktThrough && (mktThrough.has(t) === act)) mktCorrect++;
      // full wording for the tooltip, short for the (fixed-width) card so nothing clips:
      // "best 3rd" was the only label too long, and "through" -> "in" keeps a tidy in/out pair.
      const predFull = pred ? (predType[t] === "3rd" ? "best 3rd" : predType[t]) : "out";
      const predShort = pred ? (predType[t] === "3rd" ? "3rd" : predType[t]) : "out";
      const cf = bubble.has(t) ? ` <span class="gc-cf" title="a coin-flip call, we rated it 40–60%">⚖</span>` : "";
      // the market's verdict in gold: Kalshi's pre-kickoff prices, top-32 by price =
      // "through" (exactly 32 advance; a flat 50% would call 33 in).
      let mk = "";
      if (mktThrough) {
        const said = mktThrough.has(t), mok = said === act;
        mk = `<span class="gc-mkt ${mok ? "ok" : "no"}" title="market (Kalshi pre-kickoff ${pct(KQ[t] || 0, 0)}): said ${said ? "through" : "out"} · ${mok ? "right" : "wrong"}">${mok ? "✓" : "✗"}</span>`;
      }
      return `<div class="gc-row ${ok ? "ok" : "no"}" title="we predicted ${predFull} · actually ${act ? "qualified" : "eliminated"}">
        <span class="gc-res">${ok ? "✓" : "✗"}</span>
        <span class="gc-team">${flag(t)}${TLA3(t)}</span>
        <span class="gc-detail">said <b>${predShort}</b>${cf} → ${act ? "in" : "out"}</span>${mk}</div>`;
    }).join("");
    return `<div class="gc-card"><div class="gc-head"><span>Group ${g}</span><span class="gc-score">${gh}/4 right</span></div>${rows}</div>`;
  }).join("");
  if ($("rc-groups-lead")) $("rc-groups-lead").innerHTML =
    `One card per group, every team listed in its <em>final</em> order. For each we show what we called before kickoff, <b>1st</b>, <b>2nd</b> or <b>best 3rd</b> to go through, or <b>out</b>, and what happened. <b class="rc-key ok">✓</b> = we got it right, <b class="rc-key no">✗</b> = wrong, <b class="rc-key">⚖</b> = we'd rated it a coin-flip. <strong>${correct} of ${total}</strong> teams called correctly.
    The <span class="gc-mkt-key">gold ✓/✗</span> is the same grade for the <strong>prediction
    market</strong> (Kalshi's pre-kickoff prices, top 32 = through): <strong>${mktCorrect} of ${total}</strong>
    right, and on probabilities it beat us, 0.426 log-loss to our 0.529, it knew squad news we
    deliberately exclude. On the page like everything else.`;
  $("rc-groups").innerHTML = grpHTML;
  if ($("rc-gb")) {
    const gv = (p) => (p.p != null ? p.p : p.P_golden_boot);
    const eg = (eve.golden_boot || []).slice(0, 5),
      ng = (WC26.golden_boot || []).filter((p) => (p.p != null ? p.p : p.P_golden_boot) >= 0.001).slice(0, 5);
    // small gold tag with the market's pre-tournament quote (implied probability), only
    // on the eve column and only for the four names the market actually priced.
    const mq = {}; Object.entries(WC26.golden_boot_market || {}).forEach(([pl, o]) => { mq[pl] = 100 / (o + 100); });
    const col = (list, withMkt) => list.map((p, i) => `<div class="rc-gbrow"><span>${i + 1}. ${flag(p.team)}${p.player}${withMkt && mq[p.player] != null ? ` <i class="gb-mkt" title="the bookmakers' pre-tournament quote, implied probability">market ${pct(mq[p.player], 0)}</i>` : ""}</span><b>${pct(gv(p), 0)}</b></div>`).join("");
    $("rc-gb").innerHTML = `<div class="rc-gbcols"><div><div class="rc-gbh">Pre-tournament pick</div>${col(eg, true)}</div><div><div class="rc-gbh">The race now</div>${col(ng, false)}</div></div>`;
  }
}

/* ---------- knockouts graded: our bracket vs reality ---------- */
if (WC26.bracket_dists && $("rc-ko")) {
  const roundName = (mn) => mn <= 88 ? "Round of 32" : mn <= 96 ? "Round of 16" : mn <= 100 ? "Quarter-finals" : mn <= 102 ? "Semi-finals" : "Final";
  // newest phase first, and newest tie first within it
  const played = WC26.bracket_dists.filter((m) => m.winner).sort((a, b) => b.match - a.match);
  if (played.length) {
    let hits = 0, mktHits = 0, mktN = 0, lastRound = null;
    const rows = played.map((m) => {
      const rd = roundName(m.match);
      const phase = rd !== lastRound ? `<div class="ko-phase">${rd}</div>` : "";
      lastRound = rd;
      const fav = m.pH >= m.pA ? m.home : m.away;   // model's pre-match pick for the tie
      const ok = fav === m.winner; if (ok) hits++;
      const cf = Math.max(m.pH, m.pD, m.pA) < 0.42 ? `<span class="cf-badge">⚖ coin-flip</span>` : "";
      // probability of what actually happened: the draw resolves (ET + pens) in
      // proportion to each side's 90-min win chance; we quote the model's pre-match
      // chance that the REAL advancer went through (right call -> above 50, wrong -> below).
      const adH = m.pH + m.pD * (m.pH / (m.pH + m.pA || 1));
      const winThru = m.winner === m.home ? adH : 1 - adH;
      // what the MARKET had said (archived odds, last pre-kickoff fetch, margin removed);
      // rendered as its own right-hand column, next to the model's probability.
      let mkt = `<span class="ko-mkt na" title="no archived pre-match odds, the archive begins 29 June">market n/a</span>`;
      if (m.market) {
        const k = m.market, kFav = k.pH >= k.pA ? m.home : m.away;
        const kAdH = k.pH + k.pD * (k.pH / (k.pH + k.pA || 1));
        const kWinThru = m.winner === m.home ? kAdH : 1 - kAdH;
        const kOk = kFav === m.winner; mktN++; if (kOk) mktHits++;
        mkt = `<span class="ko-mkt ${kOk ? "ok" : "no"}" title="the bookmakers' pre-match chance of the side that actually went through (margin removed); ✓ = their pick advanced">market ${kOk ? "✓" : "✗"} ${pct(kWinThru, 0)}</span>`;
      }
      const heat = MD[m.home + "|" + m.away] ? " clickable" : "";
      return phase + `<div class="ko-row ${ok ? "ok" : "no"}${heat}" data-home="${m.home}" data-away="${m.away}">
        <span class="ko-match">${flag(m.home)}${TLA3(m.home)} ${m.actual[0]}–${m.actual[1]} ${TLA3(m.away)}${flag(m.away)}${heat ? ' <span class="mh-hint">heatmap ▸</span>' : ""}</span>
        <span class="ko-call">${ok ? "✓" : "✗"} backed ${flag(fav)}${TLA3(fav)} · ${flag(m.winner)}${TLA3(m.winner)} through ${cf}</span>
        ${mkt}
        <b class="ko-prob" title="model's pre-match chance of the side that actually went through (above 50% = called it)">${pct(winThru, 0)}</b></div>`;
    }).join("");
    const mktLine = mktN ? ` The market called <strong>${mktHits} of ${mktN}</strong>${mktN < played.length ? " (no archived odds for the rest)" : ""}.` : "";
    $("rc-ko").innerHTML = `<p class="chart-cap"><strong>${hits} of ${played.length}</strong> knockout ties called right so far.${mktLine}</p>` + rows;
    $("rc-ko").querySelectorAll(".ko-row.clickable").forEach((r) =>
      r.addEventListener("click", () => showHeat(r.dataset.home, r.dataset.away)));
  } else {
    $("rc-ko").innerHTML = `<p class="chart-cap">The knockouts haven't kicked off yet, this fills in tie by tie.</p>`;
  }
}

/* ---------- best calls / biggest surprises (from match_dists) ---------- */
if (WC26.match_dists && $("track-best")) {
  // model probability assigned to the outcome that actually happened (W/D/L)
  // pa = probability the model gave the OUTCOME (win/draw/loss) that happened, not the
  // exact scoreline. "Best calls" = genuinely open matches (no side over 65%) the model
  // still called right, so blow-outs of minnows don't crowd out the real calls.
  const probOf = (m) => { const [h, a] = m.actual; return h > a ? m.pH : (h < a ? m.pA : m.pD); };
  const outLabel = (m) => { const [h, a] = m.actual; return h > a ? `${m.home} won` : (h < a ? `${m.away} won` : "draw"); };
  const outIdx = (m) => { const [h, a] = m.actual; return h > a ? "H" : (h < a ? "A" : "D"); };
  const predIdx = (m) => (m.pH >= m.pD && m.pH >= m.pA) ? "H" : (m.pA >= m.pD ? "A" : "D");
  // group games only (this panel sits under the group scorecard); knockout ties are
  // graded separately in "Called it? The knockouts".
  const played = (WC26.match_dists || []).filter((m) => m.actual)
    .map((m) => ({ ...m, pa: probOf(m), topp: Math.max(m.pH, m.pD, m.pA) }));
  // a "close call" = the model rated it a coin-flip pre-match (no outcome above 42%):
  // nailing one is impressive, missing one is forgivable.
  const cf = (m) => m.topp < 0.42 ? ` <span class="cf-badge" title="pre-match coin-flip, no result above ${pct(m.topp, 0)}">⚖ coin-flip</span>` : "";
  const row = (m) => `<div class="sb-row clickable bw-row" data-home="${m.home}" data-away="${m.away}">
    <div><span class="bw-match">${flag(m.home)}${TLA3(m.home)} ${m.actual[0]}–${m.actual[1]} ${TLA3(m.away)}${flag(m.away)}</span>
      <span class="bw-out">${outLabel(m)}</span>${cf(m)}</div>
    <div class="bw-p ${m.pa >= 0.5 ? "good" : (m.pa < 0.25 ? "bad" : "")}" title="model gave this outcome ${pct(m.pa, 1)}">${pct(m.pa, 0)}</div></div>`;
  const best = played.filter((m) => m.topp <= 0.65 && predIdx(m) === outIdx(m))
    .sort((a, b) => b.pa - a.pa).slice(0, 6);
  $("track-best").innerHTML = best.map(row).join("");
  $("track-worst").innerHTML = [...played].sort((a, b) => a.pa - b.pa).slice(0, 6).map(row).join("");
  document.querySelectorAll("#track-best .bw-row, #track-worst .bw-row").forEach((c) =>
    c.addEventListener("click", () => showHeat(c.dataset.home, c.dataset.away)));
}

/* ---------- ablations: host advantage ---------- */
if (WC26.ablations && $("host-ablation")) {
  const noHost = WC26.ablations.no_host_advantage.hosts;
  // "with home" must come from the SAME model as the counterfactual (the ablations
  // baseline): baseline_eve.csv predates the altitude deployment, and comparing across
  // model versions once showed Mexico HIGHER in the neutral world (altitude boost in
  // one number, not the other). Both sides eve-information, both current-model.
  const withHome = WC26.ablations.baseline && WC26.ablations.baseline.hosts;
  $("host-ablation").innerHTML =
    ["United States", "Mexico", "Canada"].map((team) => {
      const real = withHome ? withHome[team].P1
        : (WC26.baseline_eve && WC26.baseline_eve[team] && WC26.baseline_eve[team].P1 != null)
          ? WC26.baseline_eve[team].P1 : WC26.teams.find((t) => t.team === team).P1;
      const cf = noHost[team].P1;
      return `<div class="ab-row">
        <div class="who">${flag(team)}${team}, win the group</div>
        <div class="ab-pair"><div class="ab-track"><div class="ab-fill real" style="width:${100 * real}%"></div></div>
          <div class="ab-label">with home ${pct(real, 0)}</div></div>
        <div class="ab-pair"><div class="ab-track"><div class="ab-fill counter" style="width:${100 * cf}%"></div></div>
          <div class="ab-label">neutral ${pct(cf, 0)}</div></div>
      </div>`;
    }).join("");
}

/* ---------- ablations: xi plateau ---------- */
if (WC26.xi_tuning && $("xi-chart")) {
  const entries = Object.entries(WC26.xi_tuning.pooled)
    .map(([k, v]) => [parseFloat(k), v]).sort((a, b) => a[0] - b[0]);
  const lls = entries.map(([, v]) => v);
  const min = Math.min(...lls), max = Math.max(...lls);
  const pad = (max - min) * 4 || 1;
  $("xi-chart").innerHTML =
    `<div class="xi-bars">` + entries.map(([xi, ll]) => {
      const h = 25 + 70 * (ll - min) / pad;
      const chosen = xi === WC26.xi_tuning.chosen;
      return `<div class="xi-bar${chosen ? " chosen" : ""}" title="xi=${xi}: pooled log-loss ${ll}">
        <i style="height:${h}%"></i><span>${xi}</span></div>`;
    }).join("") + `</div>
    <div class="xi-axis"><span>← 3.8-year half-life (long memory)</span><span>4.6-month half-life (short) →</span></div>`;
  $("xi-n").textContent = WC26.xi_tuning.n_matches;
  $("xi-note").innerHTML =
    `Pooled log-loss spans <strong>${min}–${max}</strong> across a 10× range of decay
     (paired t=${WC26.xi_tuning.paired_t_extremes} between the extremes: statistically nothing).
     We pin it at the plateau centre and move on, a data choice that, measurably,
     <strong>does not matter</strong>.`;
}

/* ---------- usa case ---------- */
if ($("usa-case")) {
  const usa = WC26.teams.find((t) => t.team === "United States");
  // eve information set, current model (ablations baseline) so it matches the
  // neutral-world counterfactual; falls back to the recorded eve baseline.
  const abBase = WC26.ablations && WC26.ablations.baseline && WC26.ablations.baseline.hosts;
  const usaEveP1 = abBase ? abBase["United States"].P1
    : (WC26.baseline_eve && WC26.baseline_eve["United States"]
      && WC26.baseline_eve["United States"].P1 != null) ? WC26.baseline_eve["United States"].P1 : usa.P1;
  const rows = [
    ["Model (Elo + home)", usaEveP1, "linear-gradient(90deg, var(--accent2), var(--accent))"],
    ["Market (Kalshi)", WC26.kalshi_usa_group, "var(--gold)"],
  ];
  const cfP1 = WC26.ablations ? WC26.ablations.no_host_advantage.hosts["United States"].P1 : null;
  if (cfP1 !== null) rows.push(["Model, neutral world", cfP1, "#51618f"]);
  // grade the call once the group is decided: who actually won group D
  const gD = WC26.standings && WC26.standings.D;
  const dDone = gD && gD.every((r) => r.P >= 3);
  const verdict = dDone
    ? (gD[0].team === "United States"
      ? ` The group is decided: <strong>the USA won it</strong>.`
      : ` The group is decided: <strong>${gD[0].team} won it</strong>, the USA finished ${["1st","2nd","3rd","4th"][gD.findIndex((r) => r.team === "United States")]}.`)
    : "";
  $("usa-case").innerHTML = `<div class="usa-rows">` +
    rows.map(([src, p, bg]) => `<div class="usa-row">
      <span class="src">${src}</span>
      <div class="usa-track"><i style="width:${100 * p / 0.6}%; background:${bg}"></i></div>
      <span class="num">${pct(p, 0)}</span></div>`).join("") +
    `</div><p class="mini-note" style="margin-top:8px">🇺🇸 USA win group D, three views of the same question.${verdict}</p>`;
}

/* ---------- altitude card ---------- */
if (WC26.altitude && WC26.ablations && WC26.ablations.no_altitude && $("altitude-card")) {
  const m = WC26.altitude;
  // Same-run eve comparison (baseline vs no_altitude from the same ablation
  // batch): the live conditioned forecast would drift against the snapshot
  // (eliminated teams showing phantom deltas).
  const B = (WC26.ablations.baseline || {}).P_champion || null;
  const na = WC26.ablations.no_altitude.P_champion;
  const movers = WC26.teams
    .map((t) => ({ team: t.team, d: (B ? (B[t.team] || 0) : t.P_champion) - (na[t.team] || 0) }))
    .filter((x) => Math.abs(x.d) >= 0.001)
    .sort((a, b) => Math.abs(b.d) - Math.abs(a.d)).slice(0, 5).sort((a, b) => b.d - a.d);
  $("altitude-card").innerHTML =
    `<details class="tech"><summary>the numbers, for the curious</summary><div class="boot-sd">
      <span>OOS log-loss <b>${m.oos_delta}</b></span>
      <span>paired t <b>${m.t_paired}</b></span>
      <span>β <b>${m.beta_altitude_per_km}</b>/km</span>
      <span>tested on <b>${m.n}</b> CONMEBOL qualifiers</span>
    </div></details>
    <p class="usa-key">Pre-tournament title odds, <b>with</b> the altitude tilt minus <b>without</b> it:
    <span class="k-up">green gains</span>, <span class="k-dn">red pays</span>.</p>` +
    movers.map((x) => `<div class="usa-row">
      <span class="src">${flag(x.team)}${x.team} title odds</span>
      <div class="usa-track"><i style="width:${100 * Math.min(1, Math.abs(x.d) / 0.012)}%;
        background:${x.d > 0 ? "linear-gradient(90deg, var(--accent2), var(--accent))" : "#8f5161"}"></i></div>
      <span class="num">${x.d > 0 ? "+" : ""}${(100 * x.d).toFixed(1)}pp</span></div>`).join("");
  $("altitude-note").innerHTML =
    `Our most decisive trial (t=${m.t_paired}). Only two 2026 venues sit high — Mexico City (2,240 m)
     and Zapopan — so the tilt bites there and nowhere else: <strong>Mexico gains</strong> (that thin
     air is what its squad trains in), sea-level sides whose road runs through those venues
     <strong>pay</strong> (England's likely knockout path did), and everyone else shifts a little
     as rivals strengthen or weaken around them.`;
}

/* ---------- fatigue card ---------- */
if (WC26.fatigue && WC26.ablations && WC26.ablations.no_fatigue && $("fatigue-card")) {
  const m = WC26.fatigue.meta;
  // Same-run eve comparison, like the altitude card (see comment there).
  const Bf = (WC26.ablations.baseline || {}).P_champion || null;
  const nf = WC26.ablations.no_fatigue.P_champion;
  const movers = WC26.teams
    .map((t) => ({ team: t.team, d: (Bf ? (Bf[t.team] || 0) : t.P_champion) - (nf[t.team] || 0), z: WC26.fatigue.z[t.team] }))
    .sort((a, b) => Math.abs(b.d) - Math.abs(a.d)).slice(0, 4).sort((a, b) => b.d - a.d);
  $("fatigue-card").innerHTML =
    `<details class="tech"><summary>the numbers, for the curious</summary><div class="boot-sd">
      <span>OOS log-loss <b>${m.oos_delta}</b></span>
      <span>β <b>${m.beta_fatigue}</b>/z</span>
      <span>folds <b>${m.n_folds}</b></span>
    </div></details>` +
    movers.map((x) => `<div class="usa-row">
      <span class="src">${flag(x.team)}${x.team} (load ${x.z > 0 ? "+" : ""}${x.z}σ)</span>
      <div class="usa-track"><i style="width:${100 * Math.min(1, Math.abs(x.d) / 0.025)}%;
        background:${x.d > 0 ? "linear-gradient(90deg, var(--accent2), var(--accent))" : "#8f5161"}"></i></div>
      <span class="num">${x.d > 0 ? "+" : ""}${(100 * x.d).toFixed(1)}pp</span></div>`).join("");
  $("fatigue-note").innerHTML =
    `More minutes in the legs, fewer goals on the pitch. The sign is stable but the file is thin
     (two World Cups): admitted <strong>on probation</strong>. France pays the most, the heaviest
     squad in the tournament.`;
}

/* ---------- climate (rejected) card ---------- */
if (WC26.climate && $("climate-card")) {
  const c = WC26.climate;
  $("climate-card").innerHTML = `<details class="tech"><summary>the numbers, for the curious</summary><div class="boot-sd">
    <span>OOS log-loss <b>+${c.oos_delta}</b> (worse)</span>
    <span>paired t <b>+${c.t_paired}</b></span>
    <span>verdict <b style="color:#f87171">${c.verdict}</b></span>
  </div></details>`;
}

/* ---------- bootstrap card ---------- */
if (WC26.bootstrap && WC26.ablations && WC26.ablations.no_param_uncertainty && $("boot-card")) {
  $("boot-b").textContent = WC26.bootstrap.B;
  const sd = WC26.bootstrap.sd;
  $("boot-card").innerHTML = `<details class="tech"><summary>the numbers, for the curious</summary><div class="boot-sd">` +
    Object.entries(sd).map(([k, v]) => `<span>${k.replace("beta_", "β ")} <b>±${v}</b></span>`).join("") +
    `</div></details>`;
  const pe = WC26.ablations.no_param_uncertainty.P_champion;
  const deltas = WC26.teams.map((t) => Math.abs(t.P_champion - (pe[t.team] || 0)));
  const mean = deltas.reduce((a, b) => a + b, 0) / deltas.length;
  $("boot-delta").textContent = "±" + (100 * mean).toFixed(2) + " points";
}

/* ---------- model lab (shadow scoreboard) ---------- */
if (WC26.shadow_scores && $("lab-board")) {
  // honest league table: sorted best-first by live log-loss, the deployed model sits
  // wherever it currently ranks (the ▶ badge marks it). Bars measure the EDGE over the
  // know-nothing baseline, so longer bar = better, consistent with lower number = better.
  const rows = [...WC26.shadow_scores].sort((x, y) => x.log_loss - y.log_loss);
  const n = rows[0]?.n || 0;
  const spread = rows[rows.length - 1].log_loss - rows[0].log_loss;
  const uni = WC26.uniform_logloss;
  const best = rows[0].log_loss;
  const w = (v) => (100 * (uni - v)) / (uni - best);
  const label = (v) => v === "Elo only" ? "Elo only (all tilts off)" : v;
  $("lab-board").innerHTML = rows.map((r, i) => {
    const main = r.variant === "Full model";
    const shadow = r.variant.includes("shadow");
    const col = main ? "linear-gradient(90deg, var(--accent2), var(--accent))" : shadow ? "var(--gold)" : "#51618f";
    return `<div class="bar-row">
      <div class="who">${i + 1}. ${main ? `<b>${label(r.variant)}</b> <span class="prod-badge">▶ in prod</span>` : label(r.variant)}</div>
      <div class="bar-track"><div class="bar-fill" style="width:${w(r.log_loss)}%;background:${col}"></div></div>
      <div class="val">${r.log_loss.toFixed(3)}</div>
    </div>`;
  }).join("");
  $("lab-note").innerHTML =
    `A live league table: every line is the same engine with one ingredient added or removed, ranked
     best-first by log-loss on the ${n} matches played (lower number = better; the bar shows the edge over
     the know-nothing baseline at ${uni.toFixed(3)}, so longer bar = better). The ▶ badge marks the model
     actually in production, wherever it ranks today. The gold bars are shadow bets that live here and
     <strong>only</strong> here. Caveat before reading too much: the whole field is spread by just
     <strong>${spread.toFixed(3)}</strong> log-loss, statistically tied over so few games.
     <strong>This live board never decides what goes in the model, the 345-match backtest does.</strong>`;
}

/* ---------- footer ---------- */
if ($("footer-meta")) {
  $("footer-meta").textContent =
    `Generated ${WC26.generated} · ${WC26.model_version} · ${WC26.n_sims.toLocaleString("en-US")} simulations, seed ${WC26.seed} · ` +
    `WC2022 backtest log-loss ${WC26.backtest.log_loss_model} (uniform ${WC26.backtest.log_loss_uniform}).`;
}

/* ---------- how it's doing: live track record + real standings ---------- */
if (WC26.scoring && WC26.scoring.n && $("track-head")) {
  const s = WC26.scoring;
  $("track-head").innerHTML = `
    <div class="stat"><div class="v">${s.log_loss}</div><div class="k">live log-loss (uniform ${s.uniform})</div></div>
    <div class="stat"><div class="v">${s.n}</div><div class="k">real matches scored</div></div>
    <div class="stat"><div class="v">${pct(s.fav_predicted,0)} → ${pct(s.fav_observed,0)}</div><div class="k">favourites: predicted vs won</div></div>`;
  const M = { H: "home win", D: "draw", A: "away win" };
  if ($("track-matches")) {
    // last 5 played matches, most recent first: knockouts (bracket_dists) are the newest,
    // then the latest group games.
    const koN = (WC26.bracket_dists || []).filter((m) => m.winner)
      .sort((a, b) => b.match - a.match)
      .map((m) => { const [h, a] = m.actual; return {
        home: m.home, away: m.away, score: `${h}-${a}`,
        pa: h > a ? m.pH : (h < a ? m.pA : m.pD),
        winner: m.winner, pred: m.pH >= m.pA ? m.home : m.away }; });  // model's pick to go through
    // s.matches now spans group + KO; KO ties already come from bracket_dists above
    // (with the model's pick + who went through), so drop them here to avoid doubles.
    const koPairs = new Set(koN.map((m) => m.home + "|" + m.away).concat(koN.map((m) => m.away + "|" + m.home)));
    const grpN = [...s.matches].reverse()
      .filter((m) => !koPairs.has(m.home + "|" + m.away))
      .map((m) => ({ home: m.home, away: m.away, score: m.score, pa: m.p_realised, winner: null, pred: null }));
    const last5 = [...koN, ...grpN].slice(0, 5);
    $("track-matches").innerHTML = last5.map((m) => {
      const good = m.pa >= 0.45;
      const has = MD[m.home + "|" + m.away] ? "clickable" : "";
      const hint = `<span class="mh-hint">${has ? "distribution ▸" : ""}</span>`;
      const [hg, ag] = (m.score || "-").split(/[–-]/);
      const advOk = m.winner && m.pred === m.winner;
      const adv = m.winner ? `<span class="sb-adv ${advOk ? "ok" : "no"}" title="model's pick to advance vs who actually went through">
        ${advOk ? "✓" : "✗"} said ${flag(m.pred)}${TLA3(m.pred)} · ${flag(m.winner)}${TLA3(m.winner)} through</span>` : "";
      return `<div class="sb-row ${has}" data-home="${m.home}" data-away="${m.away}">
        <div class="sb-match">
          <span class="sb-team">${flag(m.home)}${m.home}</span>
          <span class="sb-score">${hg ?? ""}<i>–</i>${ag ?? ""}</span>
          <span class="sb-team away">${m.away}${flag(m.away)}</span>
          <span class="sb-cf">${coinFlipBadge(m.home, m.away)}</span>${adv}${hint}
        </div>
        <div class="sb-p ${good ? "win" : "miss"} tnum" title="probability the model gave to what actually happened">${pct(m.pa, 0)}</div>
      </div>`;
    }).join("");
    $("track-matches").querySelectorAll(".sb-row.clickable").forEach((row) =>
      row.addEventListener("click", () => showHeat(row.dataset.home, row.dataset.away)));
  }
  if (WC26.standings && $("track-standings")) {
    $("track-standings").innerHTML = Object.keys(WC26.standings).sort().map((g) => {
      const rows = WC26.standings[g].map((r, i) => `
        <div class="row"><span>${i < 2 ? "<b>" : ""}${flag(r.team)}${r.team}${i < 2 ? "</b>" : ""}</span>
          <span>${r.Pts}p · ${r.GD > 0 ? "+" : ""}${r.GD}</span></div>`).join("");
      return `<div class="tlg"><b>GROUP ${g}</b>${rows}</div>`;
    }).join("");
  }
}

/* ---------- mobile nav: hide the sticky pills while scrolling down ---------- */
(() => {
  const toc = document.querySelector(".toc");
  if (!toc) return;
  let lastY = window.scrollY;
  window.addEventListener("scroll", () => {
    const y = window.scrollY;
    if (window.innerWidth <= 760) toc.classList.toggle("toc-hide", y > lastY && y > 140);
    else toc.classList.remove("toc-hide");
    lastY = y;
  }, { passive: true });
})();
